6	const input = readFileSync(0, "utf-8");
7	const scenario: Scenario = JSON.parse(input);
8	
9	for (const step of scenario.steps) {
10	  if (step.op === "quote") {
11	    for (const item of step.items) {
12	      if (!KNOWN_ITEM_TYPES.has(item.type)) {
13	        process.stderr.write(`Unknown item type: ${item.type}\n`);
14	        process.exit(1);
15	      }
16	    }
17	  }
